<script lang="ts">import{onMount}from'svelte';import StaxAudio from'$lib/components/StaxAudio.svelte';import StaxScene from'$lib/components/stax/StaxScene.svelte';import CastPlayerFrame from'./CastPlayerFrame.svelte';import MatchResult from'./MatchResult.svelte';import MatchStandings from'./MatchStandings.svelte';import{getRoom,subscribeRoomPlayers,type RoomPlayer}from'$lib/firebase/rooms';import{getStaxStart,subscribeStaxLifecycle,subscribeStaxProgress,type StaxLifecycle,type StaxProgress}from'$lib/firebase/stax';import{LagIndicator}from'$lib/presentation/lag';let code='',error='',chainCueSignal=0,players:RoomPlayer[]=[],progress:(StaxProgress&{displayLag?:number})[]=[],lifecycle:StaxLifecycle|undefined,audioEnabled=false,presentedTerminalPlayers=new Set<string>();const lag=new LagIndicator();let stop=()=>{},stopPlayers=()=>{},stopLife=()=>{};onMount(()=>{void load();return()=>{stop();stopPlayers();stopLife()}});const receiveProgress=(next:StaxProgress[])=>{progress=next.map(x=>({...x,displayLag:lag.sample(x.playerId,x.lag,performance.now())}));const presented=new Set(presentedTerminalPlayers);for(const player of next)if(!['cleared','lost'].includes(player.state.phase))presented.delete(player.playerId);presentedTerminalPlayers=presented};async function load(){try{code=new URL(location.href).searchParams.get('code')??'';const room=await getRoom(code);stopPlayers=subscribeRoomPlayers(room.id,p=>players=p,e=>error=e.message);if(!room.activeGameId)throw new Error('Waiting for a game.');audioEnabled=(await getStaxStart(room.activeGameId)).audioOutput==='cast';stop=subscribeStaxProgress(room.activeGameId,receiveProgress,e=>error=e.message);stopLife=subscribeStaxLifecycle(room.activeGameId,l=>lifecycle=l,e=>error=e.message)}catch(e){error=e instanceof Error?e.message:String(e)}}const name=(id:string)=>players.find(p=>p.uid===id)?.displayName??'Player';const presentationComplete=(id:string)=>presentedTerminalPlayers=new Set([...presentedTerminalPlayers,id]);$:standings=(lifecycle?.playerIds??[]).map(id=>({playerId:id,name:name(id),score:lifecycle?.scores[id]??0})).sort((a,b)=>b.score-a.score);$:terminalPresentationsComplete=!lifecycle?.finished||lifecycle.terminalPlayerIds.every(id=>presentedTerminalPlayers.has(id));</script>
<StaxAudio enabled={audioEnabled} phase={progress.some(p=>p.state.phase==='lost')?'lost':progress.some(p=>p.state.phase==='cleared')?'cleared':'playing'} survived={progress.reduce((n,p)=>n+p.state.survived,0)} placements={progress.reduce((n,p)=>n+p.state.placements,0)} chains={chainCueSignal} misses={progress.reduce((n,p)=>n+p.state.misses,0)} returns={progress.reduce((n,p)=>n+p.state.throws,0)}/><main><header>STAX · ROOM {code}</header>{#if error}<h1 role="alert">{error}</h1>{:else}<section>{#each progress as player}<CastPlayerFrame name={name(player.playerId)} lost={player.state.phase==='lost'} lag={player.displayLag} hashMatches={player.hashMatches}><StaxScene state={player.state} label={`${name(player.playerId)} Stax ramp`} onChainCue={()=>chainCueSignal++} onTerminalPresentationComplete={()=>presentationComplete(player.playerId)}/><p>SCORE {player.state.score} · {player.state.objective.progress}/{player.state.objective.target} · MISSES {player.state.misses}/{player.state.missLimit}</p><p>WAVES {lifecycle?.scores[player.playerId]??0}/3</p></CastPlayerFrame>{/each}</section>{#if lifecycle?.finished&&terminalPresentationsComplete}<MatchResult title={lifecycle.matchComplete?'RACE COMPLETE':'WAVE COMPLETE'} interactive={false} ready={lifecycle.readyPlayerIds.length} total={lifecycle.playerIds.length}><MatchStandings title="WAVE RACE" entries={standings}/></MatchResult>{/if}{/if}</main>
<style>main{min-height:100vh;padding:1rem 2vw}header{border-bottom:1px solid #343746;padding-bottom:.5rem;color:var(--yellow)}section{min-height:88dvh;display:flex;align-items:center;justify-content:center;gap:clamp(.5rem,2vw,2rem);flex-wrap:wrap}section :global(.scene){width:min(38vw,58dvh,540px)}p{margin:.2rem;font-size:.65rem;color:var(--muted)}</style>
